1	/*
2	* @info Vector Prefetch Unit
3	*
4	* @author VLSI Lab, EE dept., Democritus University of Thrace
5	*
6	*/
7	`ifdef MODEL_TECH
8	    `include "vstructs.sv"
9	`endif
10	module vmu_tp_eng #(
11	    parameter int REQ_DATA_WIDTH     = 256,
12	    parameter int VECTOR_REGISTERS   = 32 ,
13	    parameter int VECTOR_LANES       = 8  ,
14	    parameter int DATA_WIDTH         = 32 ,
15	    parameter int ADDR_WIDTH         = 32 ,
16	    parameter int MICROOP_WIDTH      = 5  ,
17	    parameter int VECTOR_TICKET_BITS = 4
18	) (
19	    input  logic                                clk              ,
20	    input  logic                                rst_n            ,
21	    //Input Interface
22	    input  logic                                valid_in         ,
23	    input  memory_remapped_v_instr              instr_in         ,
24	    output logic                                ready_o          ,
25	    //RF write Interface
26	    output logic                                wrtbck_req_o     ,
27	    input  logic                                wrtbck_grant_i   ,
28	    output logic [            VECTOR_LANES-1:0] wrtbck_en_o      ,
29	    output logic [$clog2(VECTOR_REGISTERS)-1:0] wrtbck_reg_o     ,
30	    output logic [ VECTOR_LANES*DATA_WIDTH-1:0] wrtbck_data_o    ,
31	    output logic [      VECTOR_TICKET_BITS-1:0] wrtbck_ticket_o  ,
32	    //RF Writeback Probing Interface
33	    output logic [$clog2(VECTOR_REGISTERS)-1:0] wrtbck_reg_a_o   ,
34	    input  logic                                wrtbck_locked_a_i,
35	    input  logic [      VECTOR_TICKET_BITS-1:0] wrtbck_ticket_a_i,
36	    output logic [$clog2(VECTOR_REGISTERS)-1:0] wrtbck_reg_b_o   ,
37	    input  logic                                wrtbck_locked_b_i,
38	    input  logic [      VECTOR_TICKET_BITS-1:0] wrtbck_ticket_b_i,
39	    //Unlock Interface
40	    output logic                                unlock_en_o        ,
41	    output logic [$clog2(VECTOR_REGISTERS)-1:0] unlock_reg_a_o     ,
42	    output logic [$clog2(VECTOR_REGISTERS)-1:0] unlock_reg_b_o     ,
43	    output logic [      VECTOR_TICKET_BITS-1:0] unlock_ticket_o    ,
44	    //Request Interface
45	    input  logic                                grant_i          ,
46	    output logic                                req_en_o         ,
47	    output logic [              ADDR_WIDTH-1:0] req_addr_o       ,
48	    output logic [           MICROOP_WIDTH-1:0] req_microop_o    ,
49	    output logic [  $clog2(REQ_DATA_WIDTH/8):0] req_size_o       ,
50	    output logic [      $clog2(VECTOR_LANES):0] req_ticket_o     ,
51	    // Incoming Data from Cache
52	    input  logic                                resp_valid_i     ,
53	    input  logic [      $clog2(VECTOR_LANES):0] resp_ticket_i    ,
54	    input  logic [  $clog2(REQ_DATA_WIDTH/8):0] resp_size_i      ,
55	    input  logic [          REQ_DATA_WIDTH-1:0] resp_data_i      ,
56	    //Sync Interface
57	    output logic                                is_busy_o
58	);
59	
60	    localparam int ELEMENT_ADDR_WIDTH   = $clog2(VECTOR_LANES);
61	    localparam int VREG_ADDR_WIDTH      = $clog2(VECTOR_REGISTERS);
62	    localparam int MAX_MEM_SERVED_LIMIT = REQ_DATA_WIDTH / DATA_WIDTH;
63	    localparam int MAX_RF_SERVED_COUNT  = VECTOR_REGISTERS;
64	    localparam int MAX_SERVED_COUNT     = (VECTOR_REGISTERS > MAX_MEM_SERVED_LIMIT) ? MAX_MEM_SERVED_LIMIT
65	                                                                                    : VECTOR_REGISTERS;
66	
67	    //=======================================================
68	    // REGISTERS
69	    //=======================================================
70	    logic [1:0][VECTOR_LANES-1:0][DATA_WIDTH-1:0] scratchpad;
71	
72	    logic [                                    1:0][VECTOR_LANES-1:0] pending_elem        ;
73	    logic [                                    1:0][VECTOR_LANES-1:0] served_elem         ;
74	    logic [                                    1:0][VECTOR_LANES-1:0] active_elem         ;
75	    logic [                      MICROOP_WIDTH-1:0]                   microop_r           ;
76	    logic [                 VECTOR_TICKET_BITS-1:0]                   ticket_r            ;
77	    logic [                    VREG_ADDR_WIDTH-1:0]                   rdst_r              ;
78	    logic [                    VREG_ADDR_WIDTH-1:0]                   orig_rdst_r         ;
79	    logic [                                    4:0]                   last_ticket_src2_r  ;
80	    logic [$clog2(VECTOR_REGISTERS*VECTOR_LANES):0]                   instr_vl_r          ;
81	    logic [                    VREG_ADDR_WIDTH-1:0]                   current_exp_loop_r  ;
82	    logic [                    VREG_ADDR_WIDTH-1:0]                   max_expansion_r     ;
83	    logic [                 ELEMENT_ADDR_WIDTH-1:0]                   current_pointer_wb_r;
84	    logic [                         ADDR_WIDTH-1:0]                   stride_r            ;
85	    logic [                                    1:0]                   size_r              ;
86	    logic                                                             current_row         ;
87	    logic [                    VREG_ADDR_WIDTH-1:0]                   row_0_rdst          ;
88	    logic [                    VREG_ADDR_WIDTH-1:0]                   row_1_rdst          ;
89	
90	    logic [                         ADDR_WIDTH-1:0]                   base_addr_r         ;
91	    logic [                                   15:0]                   image_size_r        ;
92	    logic [                                   15:0]                   kernel_size_r       ;
93	    logic [                                   15:0]                   win_row_num_r       ;
94	    logic [                                   15:0]                   win_col_num_r       ;
95	    //=======================================================
96	    // WIRES
97	    // =======================================================
98	    logic [$clog2(VECTOR_REGISTERS*VECTOR_LANES):0] total_remaining_elements    ;
99	    logic [$clog2(VECTOR_REGISTERS*VECTOR_LANES):0] nxt_total_remaining_elements;
100	    logic [                   ELEMENT_ADDR_WIDTH:0] loop_remaining_elements     ;
101	    logic [                                   15:0] row_remaining_el            ;
102	    logic [                 ELEMENT_ADDR_WIDTH-1:0] nxt_elem                    ;
103	    logic [                   ELEMENT_ADDR_WIDTH:0] el_served_count             ;
104	    logic [                   ELEMENT_ADDR_WIDTH:0] resp_el_count               ;
105	    logic [            VECTOR_LANES*DATA_WIDTH-1:0] data_vector                 ;
106	    logic [                         VECTOR_LANES:0] current_pointer_oh          ;
107	    logic [                         VECTOR_LANES:0] current_served_th           ;
108	    logic [                         VECTOR_LANES:0] resp_elem_th                ;
109	    logic [                         ADDR_WIDTH-1:0] current_addr                ;
110	    logic [                       VECTOR_LANES-1:0] nxt_pending_elem            ;
111	    logic [                       VECTOR_LANES-1:0] nxt_pending_elem_loop       ;
112	    logic [                                    1:0] nxt_size                    ;
113	    logic                                           start_new_instruction       ;
114	    logic                                           start_prefetch              ;
115	    logic                                           start_new_frame             ;
116	    logic                                           continue_instruction        ;
117	    logic                                           maxvl_reached               ;
118	    logic                                           vl_reached                  ;
119	    logic                                           do_reconfigure              ;
120	    logic                                           do_toepl_config             ;
121	    logic                                           current_finished            ;
122	    logic                                           currently_idle              ;
123	    logic                                           expansion_finished          ;
124	    logic                                           start_new_loop              ;
125	    logic                                           new_transaction_en          ;
126	    logic                                           request_ready               ;
127	    logic                                           resp_row                    ;
128	    logic                                           writeback_complete          ;
129	    logic                                           row_0_ready                 ;
130	    logic                                           row_1_ready                 ;
131	    logic                                           nxt_row                     ;
132	    logic                                           writeback_row               ;
133	    logic                                           instr_mismatch_found        ;
134	    logic [                         ADDR_WIDTH-1:0] nxt_base_addr               ;
135	    logic [                                   15:0] row_base                    ;
136	    logic [                                   15:0] col_num                     ;
137	    logic [                                   15:0] row_num                     ;
138	    logic [                                   15:0] win_row_base                ;
139	    logic [                                   15:0] addr_offset                 ;
140	    logic [                                   15:0] nxt_win_col_num             ;
141	    //=======================================================
142	    // Prefetchng FSM
143	    //=======================================================
144	    typedef enum { IDLE, ACTIVE, PREFETCH} activity_fsm_t;
145	    activity_fsm_t cur_state;
146	    activity_fsm_t nxt_state;
147	
148	    always_ff @(posedge clk or negedge rst_n) begin
149	        if(~rst_n) begin
150	            cur_state <= IDLE;
151	        end else begin
152	            cur_state <= nxt_state;
153	        end
154	    end
155	
156	    always_comb begin
157	        case (cur_state)
158	            IDLE    : nxt_state = start_new_instruction ? ACTIVE   : IDLE;
159	            ACTIVE  : nxt_state = start_prefetch        ? PREFETCH : ACTIVE;
160	            PREFETCH: nxt_state = continue_instruction  ? ACTIVE   :
161	                                  start_new_instruction ? ACTIVE   : PREFETCH;
162	            default : nxt_state = activity_fsm_t'('x);
163	        endcase
164	        if (do_reconfigure | do_toepl_config) nxt_state = IDLE;
165	    end
166	    //=======================================================
167	    // Create basic control flow
168	    //=======================================================
169	    assign ready_o             =  currently_idle;
170	    assign is_busy_o           = ~currently_idle;
171	
172	    //current instruction finished
173	    assign current_finished = ~pending_elem[current_row][nxt_elem] & expansion_finished & new_transaction_en;
174	    //currently no instructions are being served
175	    assign currently_idle = (~|pending_elem & ~|active_elem) | (cur_state === PREFETCH) | (cur_state === IDLE);
176	
177	    assign expansion_finished = maxvl_reached | vl_reached;
178	    assign maxvl_reached      = (current_exp_loop_r === (max_expansion_r-1));
179	    assign vl_reached         = (((current_exp_loop_r+1) << $clog2(VECTOR_LANES)) >= instr_vl_r);
180	
181	    //indicates a pipeline reconfiguration
182	    assign do_reconfigure        = valid_in & ready_o &  instr_in.reconfigure;
183	    //indicates new instruction starting fresh or after failed prefetch
184	    assign start_new_instruction = valid_in & ready_o & ~instr_in.reconfigure & ~do_toepl_config &
185	                                 ((cur_state === IDLE) | (cur_state === PREFETCH & instr_mismatch_found));
186	    //prefetch begins after the current instr retires
187	    assign start_prefetch        = ~|pending_elem & ~|active_elem & (cur_state === ACTIVE);
188	    assign start_new_frame       = (start_prefetch & (win_row_num_r === kernel_size_r  ))                                |
189	                                   (start_prefetch & (win_row_num_r === kernel_size_r-1) & win_col_num_r === kernel_size_r);
190	
191	    // indicates a toeplitz reconfiguration
192	    assign do_toepl_config       = valid_in & ready_o & ~instr_in.reconfigure & instr_in.microop === 7'b1110011;
193	    // indicates that the prefetch was correct and will continue with it
194	    assign continue_instruction  = valid_in & ready_o & ~instr_in.reconfigure & (cur_state === PREFETCH) & ~instr_mismatch_found;
195	    // indicates the prefetch mismatches with the instruction flow
196	    assign instr_mismatch_found  = (nxt_base_addr !== base_addr_r); //REVISIT - needs more checks
197	
198	    // Start from element 0 on the next destination vreg
199	    assign start_new_loop = (~|pending_elem[current_row] & ~expansion_finished & ~|active_elem[nxt_row]);
200	
201	    // Create the memory request control signals
202	    assign req_en_o      = request_ready;
203	    assign req_addr_o    = current_addr;
204	    assign req_microop_o = 5'b10000; //REVISIT will change based on instruction
205	    assign req_ticket_o  = {current_row,current_pointer_wb_r};
206	    always_comb begin
207	        unique case (size_r)
208	            `SZ_8   : req_size_o = el_served_count;      //el_served_count * 1
209	            `SZ_16  : req_size_o = el_served_count << 1; //el_served_count * 2
210	            `SZ_32  : req_size_o = el_served_count << 2; //el_served_count * 4
211	            default : req_size_o = 'x;
212	        endcase
213	    end
214	
215	    assign request_ready      = pending_elem[current_row][current_pointer_wb_r] & (cur_state === ACTIVE | cur_state === PREFETCH);
216	    assign new_transaction_en = request_ready & grant_i;
217	
218	    // Unlock register signals
219	    assign unlock_en_o     = writeback_complete;
220	    assign unlock_ticket_o = ticket_r;
221	    assign unlock_reg_a_o  = row_0_ready ? row_0_rdst : row_1_rdst;
222	    assign unlock_reg_b_o  = row_0_ready ? row_0_rdst : row_1_rdst;
223	
224	    // Create the writeback signals for the RF
225	    assign wrtbck_req_o       = (row_0_ready | row_1_ready) & (cur_state === ACTIVE);
226	    assign writeback_complete = wrtbck_req_o & wrtbck_grant_i;
227	    assign writeback_row      = row_0_ready ? 1'b0 : 1'b1;
228	
229	    assign row_0_ready = ~|(active_elem[0] ^ served_elem[0]) & |active_elem[0] & (wrtbck_ticket_a_i === ticket_r) & wrtbck_locked_a_i;
230	    assign row_1_ready = ~|(active_elem[1] ^ served_elem[1]) & |active_elem[1] & (wrtbck_ticket_b_i === ticket_r) & wrtbck_locked_b_i;
231	
232	    // Output aliasing
233	    assign wrtbck_en_o     = row_0_ready ? {VECTOR_LANES{writeback_complete}} & served_elem[0] :
234	                                           {VECTOR_LANES{writeback_complete}} & served_elem[1];
235	    assign wrtbck_data_o   = row_0_ready ? scratchpad[0] : scratchpad[1];
236	    assign wrtbck_reg_o    = row_0_ready ? row_0_rdst    : row_1_rdst;
237	    assign wrtbck_ticket_o = ticket_r;
238	    assign wrtbck_reg_a_o  = row_0_rdst;
239	    assign wrtbck_reg_b_o  = row_1_rdst;
240	
241	    //=======================================================
242	    // Address Generation
243	    //=======================================================
244	    assign row_num = instr_in.data1[15:0];
245	    assign col_num = instr_in.data2[15:0];
246	    always_comb begin
247	        row_base      = row_num * image_size_r;
248	        nxt_base_addr = row_base + col_num;
249	        nxt_base_addr = nxt_base_addr << 2;
250	        nxt_base_addr = nxt_base_addr + instr_in.immediate;
251	    end
252	    //Hold region base address (for each kernel once)
253	    always_ff @(posedge clk) begin
254	        if(start_new_instruction)
255	            base_addr_r <= nxt_base_addr;
256	        else if (start_new_frame)
257	            base_addr_r <= base_addr_r + stride_r;
258	    end
259	
260	    // generate current address offset
261	    always_comb begin
262	        win_row_base = win_row_num_r * image_size_r;
263	        addr_offset  = win_row_base + win_col_num_r;
264	        unique case (size_r)
265	            `SZ_8   : addr_offset = addr_offset;
266	            `SZ_16  : addr_offset = addr_offset << 1;
267	            `SZ_32  : addr_offset = addr_offset << 2;
268	            default : addr_offset = 'x;
269	        endcase
270	    end
271	
272	    assign current_addr = base_addr_r + addr_offset;
273	
274	    //Hold image & kernel sizes (needs toepl reconfig)
275	    always_ff @(posedge clk) begin
276	        if(do_toepl_config) begin
277	            image_size_r  <= instr_in.data1;
278	            kernel_size_r <= instr_in.data2;
279	        end
280	    end
281	
282	    assign nxt_win_col_num = win_col_num_r + el_served_count;
283	    // Hold the row/col progression
284	    always_ff @(posedge clk) begin
285	        if(start_new_instruction | start_new_frame) begin
286	            win_row_num_r <= 0;
287	            win_col_num_r <= 0;
288	        end else if(new_transaction_en) begin
289	            if (nxt_win_col_num == kernel_size_r) begin
290	                win_row_num_r <= win_row_num_r +1;
291	                win_col_num_r <= 'd0;
292	            end else begin
293	                win_col_num_r <= nxt_win_col_num;
294	            end
295	        end
296	    end
297	    //Hold mem op size
298	    assign nxt_size   = instr_in.microop[`MEM_SZ_RANGE_HI:`MEM_SZ_RANGE_LO];
299	    assign nxt_stride = instr_in.immediate;
300	    always_ff @(posedge clk) begin
301	        if(do_toepl_config) size_r   <= nxt_size;
302	        if(do_toepl_config) stride_r <= nxt_stride;
303	    end
304	    //=======================================================
305	    // Scratchpad maintenance
306	    //=======================================================
307	    assign resp_row = resp_ticket_i[ELEMENT_ADDR_WIDTH];
308	    // Calculate the elements that have a valid response
309	    always_comb begin
310	        unique case (size_r)
311	            `SZ_8   : resp_el_count = resp_size_i;      //el_served_count * 1
312	            `SZ_16  : resp_el_count = resp_size_i >> 1; //el_served_count * 2
313	            `SZ_32  : resp_el_count = resp_size_i >> 2; //el_served_count * 4
314	            default : resp_el_count = 'x;
315	        endcase
316	    end
317	    assign resp_elem_th = ((~('1 << resp_el_count)) << resp_ticket_i[ELEMENT_ADDR_WIDTH-1:0]);
318	
319	    // Shift data vector to match the elements positions
320	    assign data_vector = resp_data_i << resp_ticket_i[ELEMENT_ADDR_WIDTH-1:0] * 32;
321	    // Store new Data
322	    always_ff @(posedge clk) begin : scratchpad_maint
323	        for (int i = 0; i < VECTOR_LANES; i++) begin
324	            // row 0 maintenance
325	            if(resp_valid_i && !resp_row && resp_elem_th[i]) begin
326	                scratchpad[0][i] <= data_vector[i*32 +: 32];
327	            end
328	            // row 1 maintenance
329	            if(resp_valid_i && resp_row && resp_elem_th[i]) begin
330	                scratchpad[1][i] <= data_vector[i*32 +: 32];
331	            end
332	        end
333	    end
334	    // keep track of the rdst for each row
335	    always_ff @(posedge clk or negedge rst_n) begin
336	        if(~rst_n) begin
337	            row_0_rdst <= 0;
338	            row_1_rdst <= 0;
339	        end else begin
340	            // row 0 maintenance
341	            if(start_new_instruction || continue_instruction) begin
342	                row_0_rdst <= instr_in.dst;
343	            end else if(start_new_loop && !nxt_row) begin
344	                row_0_rdst <= rdst_r +1;
345	            end
346	            // row 1 maintenance
347	            if(start_new_loop && nxt_row) begin
348	                row_1_rdst <= rdst_r +1;
349	            end
350	        end
351	    end
352	    //=======================================================
353	    // Scoreboard maintenance
354	    //=======================================================
355	    assign row_remaining_el = kernel_size_r - win_col_num_r;
356	
357	    always_comb begin : proc_loop_remaining_el
358	        loop_remaining_elements = '0;
359	        for (int i = 0; i < VECTOR_LANES; i++) begin
360	            if (pending_elem[current_row][i]) loop_remaining_elements = loop_remaining_elements +1;
361	        end
362	    end
363	    assign total_remaining_elements     = instr_vl_r - (current_exp_loop_r*VECTOR_LANES);
364	    assign nxt_total_remaining_elements = instr_vl_r - ((current_exp_loop_r+1)*VECTOR_LANES);
365	
366	    always_comb begin : get_served_el_cnt
367	        if (row_remaining_el < loop_remaining_elements) begin
368	            el_served_count = row_remaining_el;
369	        end else begin
370	            el_served_count = loop_remaining_elements;
371	        end
372	        if (el_served_count > MAX_SERVED_COUNT)
373	            el_served_count = MAX_SERVED_COUNT;
374	    end
375	
376	    // Maintain current pointer and row
377	    assign nxt_row  = ~current_row;
378	    assign nxt_elem = current_pointer_wb_r +el_served_count;
379	    always_ff @(posedge clk or negedge rst_n) begin : current_ptr
380	        if(~rst_n) begin
381	            current_pointer_wb_r <= 0;
382	            current_row          <= 0;
383	        end else begin
384	            if(start_new_instruction || start_prefetch) begin
385	                current_pointer_wb_r <= 0;
386	                current_row          <= 0;
387	            end else if(start_new_loop) begin
388	                current_pointer_wb_r <= 0;
389	                current_row          <= nxt_row;
390	            end else if (current_finished) begin
391	                current_pointer_wb_r <= 0;
392	            end else if(new_transaction_en) begin
393	                current_pointer_wb_r <= nxt_elem;
394	            end
395	        end
396	    end
397	
398	    // Create new pending states
399	    always_comb begin : get_new_elem_pending
400	        // next pending state for new instruction
401	        if(instr_in.vl < VECTOR_LANES & start_prefetch)
402	            nxt_pending_elem = ~('1 << instr_vl_r);
403	        else if(instr_in.vl < VECTOR_LANES & ~start_prefetch)
404	            nxt_pending_elem = ~('1 << instr_in.vl);
405	        else
406	            nxt_pending_elem = '1;
407	        // next pending state for new loop
408	        if(nxt_total_remaining_elements < VECTOR_LANES)
409	            nxt_pending_elem_loop = ~('1 << nxt_total_remaining_elements);
410	        else
411	            nxt_pending_elem_loop = '1;
412	    end
413	
414	    // Store new pending states
415	    assign current_served_th  = (~('1 << el_served_count)) << current_pointer_wb_r;
416	    assign current_pointer_oh = 1 << current_pointer_wb_r;
417	    always_ff @(posedge clk or negedge rst_n) begin: pending_status
418	        if(~rst_n) begin
419	            pending_elem <= '0;
420	        end else begin
421	            for (int i = 0; i < VECTOR_LANES; i++) begin
422	                //row 0 maintenance
423	                if(start_new_instruction || start_prefetch)
424	                    pending_elem[0][i] <= nxt_pending_elem[i];
425	                else if(start_new_loop && !nxt_row)
426	                    pending_elem[0][i] <= nxt_pending_elem_loop[i];
427	                else if(new_transaction_en && current_served_th[i] && !current_row) // single-request
428	                    pending_elem[0][i] <= 1'b0;
429	                //row 1 maintenance
430	                if(start_new_instruction || start_prefetch)
431	                    pending_elem[1][i] <= 1'b0;
432	                else if(start_new_loop && nxt_row)
433	                    pending_elem[1][i] <= nxt_pending_elem_loop[i];
434	                else if(new_transaction_en && current_served_th[i] && current_row) // single-request
435	                    pending_elem[1][i] <= 1'b0;
436	            end
437	        end
438	    end
439	    always_ff @(posedge clk or negedge rst_n) begin : active_status
440	        if(~rst_n) begin
441	            active_elem <= '0;
442	        end else begin
443	            for (int i = 0; i < VECTOR_LANES; i++) begin
444	                // row 0 maintenance
445	                if (writeback_complete && !writeback_row)
446	                    active_elem[0][i] <= 1'b0;
447	                else if(start_new_instruction || start_prefetch)
448	                    active_elem[0][i] <= nxt_pending_elem[i];
449	                else if(start_new_loop && !nxt_row)
450	                    active_elem[0][i] <= nxt_pending_elem_loop[i];
451	                // row 1 maintenance
452	                if (writeback_complete && writeback_row)
453	                    active_elem[1][i] <= 1'b0;
454	                else if(start_new_instruction || start_prefetch)
455	                    active_elem[1][i] <= 1'b0;
456	                else if(start_new_loop && nxt_row)
457	                    active_elem[1][i] <= nxt_pending_elem_loop[i];
458	            end
459	        end
460	    end
461	    // Keep track of served elements from memory
462	    always_ff @(posedge clk or negedge rst_n) begin
463	        if(~rst_n) begin
464	            served_elem <= '0;
465	        end else begin
466	            for (int i = 0; i < VECTOR_LANES; i++) begin
467	                // row 0 maintenance
468	                if(start_new_instruction || start_prefetch) begin
469	                    served_elem[0][i] <= 1'b0;
470	                end else if(start_new_loop && !nxt_row) begin
471	                    served_elem[0][i] <= 1'b0;
472	                end else if(resp_valid_i && resp_elem_th[i] && !resp_row) begin
473	                    served_elem[0][i] <= 1'b1;
474	                end
475	                // row 1 maintenance
476	                if(start_new_instruction || start_prefetch) begin
477	                    served_elem[1][i] <= 1'b0;
478	                end else if(start_new_loop && nxt_row) begin
479	                    served_elem[1][i] <= 1'b0;
480	                end else if(resp_valid_i && resp_elem_th[i] && resp_row) begin
481	                    served_elem[1][i] <= 1'b1;
482	                end
483	            end
484	        end
485	    end
486	
487	    // Keep track of the expanions happening
488	    always_ff @(posedge clk or negedge rst_n) begin : loop_tracking
489	        if(~rst_n) begin
490	            current_exp_loop_r <= 0;
491	        end else begin
492	            if(start_new_instruction) begin
493	                current_exp_loop_r <= 0;
494	                rdst_r             <= instr_in.dst;
495	                orig_rdst_r        <= instr_in.dst;
496	            end else if (start_prefetch & ~start_new_frame) begin
497	                current_exp_loop_r <= 0;
498	            end else if (start_prefetch & start_new_frame) begin
499	                current_exp_loop_r <= 0;
500	                rdst_r             <= orig_rdst_r;
501	            end else if(start_new_loop) begin
502	                current_exp_loop_r <= current_exp_loop_r +1;
503	                rdst_r             <= rdst_r +1;
504	            end
505	        end
506	    end
507	    //Store the max expansion when reconfiguring
508	    always_ff @(posedge clk or negedge rst_n) begin : maxExp
509	        if(~rst_n) begin
510	            max_expansion_r <= 'd1;
511	        end else begin
512	            if(do_reconfigure) begin
513	                max_expansion_r <= instr_in.maxvl >> $clog2(VECTOR_LANES);
514	            end
515	        end
516	    end
517	
518	    //=======================================================
519	    // Capture Instruction Information
520	    always_ff @(posedge clk or negedge rst_n) begin : proc_vl_r
521	        if(~rst_n) begin
522	            instr_vl_r <= VECTOR_LANES;
523	        end else begin
524	            if(start_new_instruction) begin
525	                instr_vl_r <= instr_in.vl;
526	            end
527	        end
528	    end
529	    always_ff @(posedge clk) begin
530	        if(start_new_instruction) begin
531	            microop_r          <= instr_in.microop;
532	        end
533	    end
534	    always_ff @(posedge clk) begin
535	        if(start_new_instruction || continue_instruction) begin
536	            ticket_r           <= instr_in.ticket;
537	            last_ticket_src2_r <= instr_in.last_ticket_src2;
538	        end
539	    end
540	
541	//=======================================================
542	    logic stall_row_0_while_ready, stall_row_1_while_ready;
543	    logic [63:0] total_tp_stalled_due_is;
544	
545	    assign stall_row_0_while_ready = ~|(active_elem[0] ^ served_elem[0]) & |active_elem[0] & (~wrtbck_locked_a_i | wrtbck_ticket_a_i !== ticket_r);
546	    assign stall_row_1_while_ready = ~|(active_elem[1] ^ served_elem[1]) & |active_elem[1] & (~wrtbck_locked_b_i | wrtbck_ticket_b_i !== ticket_r);
547	
548	    always_ff @(posedge clk or negedge rst_n) begin
549	        if(~rst_n) begin
550	            total_tp_stalled_due_is <= 0;
551	        end else begin
552	            if (stall_row_0_while_ready | stall_row_1_while_ready)
553	                total_tp_stalled_due_is <= total_tp_stalled_due_is +1;
554	        end
555	    end
556	
557	
558	`ifdef MODEL_TECH
559	    `include "vmu_tp_eng_sva.sv"
560	`endif
561	
562	endmodule

